create index if not exists integration_outbox_org_status_available_idx on public.integration_outbox(organization_id,status,available_at,created_at);create index if not exists dead_letter_org_resolved_created_idx on public.dead_letter_events(organization_id,resolved,created_at desc);create index if not exists ai_usage_org_created_latency_idx on public.ai_usage_events(organization_id,created_at desc,latency_ms);
create table if not exists public.reliability_release_snapshots(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id)on delete cascade,status text not null check(status in('blocked','ready_for_homologation')),score integer not null check(score between 0 and 100),evidence jsonb not null,controls jsonb not null,blocking text[]not null default'{}',snapshot_hash text not null check(snapshot_hash~'^[a-f0-9]{64}$'),created_by uuid not null references public.profiles(id),created_at timestamptz not null default now(),unique(organization_id,snapshot_hash));create index if not exists reliability_snapshots_org_idx on public.reliability_release_snapshots(organization_id,created_at desc);alter table public.reliability_release_snapshots enable row level security;create policy reliability_snapshots_director_read on public.reliability_release_snapshots for select to authenticated using(organization_id=(select public.current_organization_id())and exists(select 1 from public.profiles p where p.id=auth.uid()and coalesce(p.commercial_role,case when p.role='admin'then'director'else p.role end)='director'));revoke all on public.reliability_release_snapshots from anon,authenticated;grant select on public.reliability_release_snapshots to authenticated;
